<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Kanban Board</title>
<style>
  body{font-family:Arial,sans-serif;background:#f0f2f5;margin:0;padding:20px;}
  .board{display:flex;gap:15px;}
  .column{background:white;border-radius:6px;flex:1;display:flex;flex-direction:column;height:80vh;}
  .header{padding:10px;font-weight:bold;background:#e9ecef;border-bottom:1px solid #ddd;display:flex;justify-content:space-between;align-items:center;}
  .count{background:#007bff;color:white;padding:2px 6px;border-radius:12px;font-size:0.8em;}
  .card-container{flex:1;padding:10px;overflow-y:auto;}
  .card{background:#fff;border-radius:4px;padding:10px;margin-bottom:8px;box-shadow:0 1px 3px rgba(0,0,0,.1);display:flex;justify-content:space-between;align-items:center;}
  .card-del{background:none;border:none;color:#dc3545;font-weight:bold;cursor:pointer;}
  #new-card{width:calc(100% - 80px);padding:8px;margin-right:10px;}
  #add-card{padding:8px 12px;background:#28a745;color:white;border:none;border-radius:4px;cursor:pointer;}
</style>
</head>
<body>

<h1>Kanban Board</h1>
<div style="margin-bottom:15px;">
  <input type="text" id="new-card" placeholder="New task...">
  <button id="add-card">Add Card</button>
</div>

<div class="board">
  <div id="col-todo" class="column" data-col="todo">
    <div class="header">To Do<span class="count"></span></div>
    <div class="card-container"></div>
  </div>
  <div id="col-doing" class="column" data-col="doing">
    <div class="header">Doing<span class="count"></span></div>
    <div class="card-container"></div>
  </div>
  <div id="col-done" class="column" data-col="done">
    <div class="header">Done<span class="count"></span></div>
    <div class="card-container"></div>
  </div>
</div>

<script>
(() => {
  const STORAGE_KEY = 'kanbanState';
  let state = { cards: [], nextId: 1 };

  function load() {
    const data = localStorage.getItem(STORAGE_KEY);
    if (data) state = JSON.parse(data);
  }

  function save() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }

  function createCardElement(card) {
    const el = document.createElement('div');
    el.className = 'card';
    el.draggable = true;
    el.dataset.id = card.id;

    const title = document.createElement('span');
    title.textContent = card.title;

    const delBtn = document.createElement('button');
    delBtn.className = 'card-del';
    delBtn.textContent = '✕';

    el.appendChild(title);
    el.appendChild(delBtn);

    // Drag events
    el.addEventListener('dragstart', e => {
      e.dataTransfer.setData('text/plain', card.id);
    });

    return el;
  }

  function render() {
    const cols = { todo: document.querySelector('#col-todo .card-container'),
                   doing: document.querySelector('#col-doing .card-container'),
                   done: document.querySelector('#col-done .card-container') };

    // Clear
    Object.values(cols).forEach(c => c.innerHTML = '');

    state.cards.forEach(card => {
      const el = createCardElement(card);
      cols[card.col].appendChild(el);
    });

    // Update counts
    ['todo','doing','done'].forEach(col=>{
      const countEl = document.querySelector(`#col-${col} .count`);
      const cnt = state.cards.filter(c=>c.col===col).length;
      countEl.textContent = ` ${cnt}`;
    });
  }

  function addCard(title) {
    if (!title.trim()) return;
    const card = { id: String(state.nextId++), title, col: 'todo' };
    state.cards.push(card);
    save();
    render();
  }

  function deleteCard(id) {
    state.cards = state.cards.filter(c=>c.id!==id);
    save();
    render();
  }

  // Event listeners
  document.getElementById('add-card').addEventListener('click', () => {
    const input = document.getElementById('new-card');
    addCard(input.value);
    input.value = '';
  });

  document.getElementById('new-card').addEventListener('keypress', e=>{
    if (e.key==='Enter') document.getElementById('add-card').click();
  });

  // Delete via delegation
  document.querySelectorAll('.card-container').forEach(container=>{
    container.addEventListener('click', e=>{
      if (e.target.classList.contains('card-del')) {
        const cardEl = e.target.closest('.card');
        deleteCard(cardEl.dataset.id);
      }
    });
  });

  // Drag & drop columns
  document.querySelectorAll('.column').forEach(col=>{
    col.addEventListener('dragover', e=>e.preventDefault());
    col.addEventListener('drop', e=>{
      e.preventDefault();
      const id = e.dataTransfer.getData('text/plain');
      const card = state.cards.find(c=>c.id===id);
      if (card && card.col!==col.dataset.col) {
        card.col = col.dataset.col;
        save();
        render();
      }
    });
  });

  // Init
  load();
  render();
})();
</script>
</body>
</html>
